<style lang="scss" scoped>
.avatar {
    position: relative;

    img {
        max-width: 35rem;
        border-radius: 50%;
        opacity: 0;
        animation: opacity 1s ease-in-out 1.5s forwards;
    }

    &__kubernetes {
        max-width: 15rem;
        position: absolute;
        left: -7rem;
        top: 8rem;
        transform: scale(0);
        animation: pop 0.7s ease-in-out 1.7s forwards;
    }

    &__netcore {
        max-width: 12rem;
        position: absolute;
        right: -3rem;
        top: -3.5rem;
        transform: scale(0);
        animation: pop 0.7s ease-in-out 1.9s forwards;
    }

    &__java {
        max-width: 10rem;
        position: absolute;
        right: 1rem;
        bottom: -2rem;
        transform: scale(0);
        animation: pop 0.7s ease-in-out 2.1s forwards;
    }
}

@keyframes pop {
    0% {
        transform: scale(0.3);
    }
    50% {
        transform: scale(1.1);
    }
    80% {
        transform: scale(0.89);
    }
    100% {
        transform: scale(1);
    }
}

@keyframes opacity {
    0% {
        opacity: 0;
    }
    100% {
        opacity: 1;
    }
}
</style>